<?php

namespace App\Livewire\Forms;

use Livewire\Form;

class GenericMedicineForm extends Form { public ?int $id = null; public string $name = ''; public string $code = ''; public ?string $description = null; public ?string $therapeutic_class = null; public ?string $pharmacological_class = null; public bool $controlled_drug = false; public bool $prescription_required = true; public ?string $pregnancy_warning = null; public ?string $common_indications = null; public ?string $common_contraindications = null; public ?string $common_side_effects = null; public bool $is_active = true; public function rules(): array { return ['name' => ['required'], 'code' => ['required'], 'controlled_drug' => ['boolean'], 'prescription_required' => ['boolean']]; } public function validationAttributes(): array { return ['name' => 'jina la generic']; } public function normalize(): array { return ['name' => $this->name, 'code' => str($this->code)->upper()->toString(), 'description' => $this->description, 'therapeutic_class' => $this->therapeutic_class, 'pharmacological_class' => $this->pharmacological_class, 'controlled_drug' => $this->controlled_drug, 'prescription_required' => $this->prescription_required, 'pregnancy_warning' => $this->pregnancy_warning, 'common_indications' => $this->common_indications, 'common_contraindications' => $this->common_contraindications, 'common_side_effects' => $this->common_side_effects, 'is_active' => $this->is_active]; } public function fillFromModel($model): void { $this->id = $model->id; $this->fill($model->only(array_keys($this->normalize()))); } public function resetForm(): void { $this->reset(); $this->prescription_required = true; $this->is_active = true; } }
